class Animal {
    String name;

    Animal(String name) {
        this.name = name;
    }

    void makeSound() {
        System.out.println(name + " makes a sound.");
    }
}

// Dog extends Animal — override makeSound() to print "<name> says: Woof!"

// Cat extends Animal — override makeSound() to print "<name> says: Meow!"

public class AnimalInheritance {
    public static void main(String[] args) {
        Animal a = new Animal("Generic Animal");
        Dog d = new Dog("Buddy");
        Cat c = new Cat("Whiskers");

        a.makeSound();
        d.makeSound();
        c.makeSound();
    }
}

class Vehicle {
    String brand;
    int year;

    Vehicle(String brand, int year) {
        this.brand = brand;
        this.year = year;
    }

    void describe() {
        System.out.println("Brand: " + brand + ", Year: " + year);
    }
}

class ElectricVehicle extends Vehicle {
    int rangeKm;

    // Constructor: use super() to initialise brand and year, then set rangeKm

    // Override describe(): call super.describe() then print "Range: <rangeKm> km"
}

public class SuperDemo {
    public static void main(String[] args) {
        ElectricVehicle ev = new ElectricVehicle("Tesla", 2023, 500);
        ev.describe();
    }
}

class Person {
    String name;
    Person(String name) { this.name = name; }
    public String toString() { return "Person: " + name; }
}

// Employee extends Person: adds String department
// Constructor: super(name), this.department = department
// Override toString(): "Employee: " + name + " | Dept: " + department

// Manager extends Employee: adds int teamSize
// Constructor: super(name, department), this.teamSize = teamSize
// Override toString(): "Manager: " + name + " | Dept: " + department + " | Team: " + teamSize

public class EmployeeHierarchy {
    public static void main(String[] args) {
        Person p = new Person("Alice");
        Employee e = new Employee("Bob", "Engineering");
        Manager m = new Manager("Carol", "Engineering", 8);

        System.out.println(p);
        System.out.println(e);
        System.out.println(m);
    }
}
